module RefModule(
  input clk,
  input trigger,
  input [15:0] pulse_width,
  output reg pulse
);

reg [15:0] unused_counter = 0;
reg pulse_gen = 0;

always @(posedge clk) begin
  if (trigger) begin
    pulse_gen <= 1;
    unused_counter <= 0;
  end else begin
    if (unused_counter >= pulse_width) begin
      pulse_gen <= 0;
    end
    unused_counter <= unused_counter + 1;
  end
end

always @(posedge clk) begin
  pulse <= pulse_gen;
end

endmodule
